import React from "react";
import { Link } from "react-router-dom";
import { motion } from "framer-motion";
import {
  Palette,
  Building,
  ShoppingBag,
  Megaphone,
  Star,
  TrendingUp,
  Crown,
} from "lucide-react";
import Footer from "../components/Footer"; // Make sure Footer is updated for toggle

function Home() {
  return (
    <div className="min-h-screen flex flex-col bg-white dark:bg-gray-900 text-gray-900 dark:text-gray-200">
      {/* Main content grows to push footer down */}
      <main className="flex-grow">
        {/* Hero Section */}
        <section className="relative min-h-screen flex flex-col justify-center items-center text-center bg-gradient-to-br from-black via-gray-800 to-gray-900 text-white overflow-hidden px-6 md:px-20">
          <motion.h1
            className="text-5xl md:text-6xl font-bold mb-6"
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            Godemar’s Empire
          </motion.h1>
          <motion.p
            className="text-xl mb-8 max-w-2xl"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.3 }}
          >
            Where creativity meets commerce, and vision shapes reality.
          </motion.p>
          <div className="flex flex-col md:flex-row justify-center gap-4">
            <Link to="/about">
              <motion.button
                className="px-6 py-3 bg-yellow-500 text-black font-semibold rounded-lg shadow hover:bg-yellow-600 transition"
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                Explore Our Empire
              </motion.button>
            </Link>
            <Link to="/contact">
              <motion.button
                className="px-6 py-3 bg-transparent border border-yellow-500 text-yellow-500 font-semibold rounded-lg hover:bg-yellow-500 hover:text-black transition"
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                Contact Us
              </motion.button>
            </Link>
          </div>
        </section>

        {/* About Section, Core Domains, Purpose & Vision, Why Choose Us, CTA */}
        {/* Keep all sections exactly the same as your current code */}
      </main>

      {/* Toggleable Sticky Footer */}
      <Footer />
    </div>
  );
}

export default Home;
